package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetSkipHeaderRecord() {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);
        // Set private field skipHeaderRecord to true
        boolean expected = true;
        try {
            java.lang.reflect.Field field = CSVFormat.class.getDeclaredField("skipHeaderRecord");
            field.setAccessible(true);
            field.set(csvFormat, expected);
        } catch (NoSuchFieldException | IllegalAccessException e) {
            e.printStackTrace();
        }

        // When
        boolean result = csvFormat.getSkipHeaderRecord();

        // Then
        assertEquals(expected, result);
    }
}
